echo "Downloading ${#urls[@]} images to $DEST..."
count=0
for url in "${urls[@]}"; do
  filename=$(basename "$url" | sed 's/%20/ /g')
  echo "[$((++count))/${#urls[@]}] $filename"
  curl -sL -o "$DEST/$filename" "$url"
done
echo "Done! Downloaded $count images."
